'use client';

import { useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import Link from 'next/link';
import { Card, CardHeader, CardTitle, CardContent, CardDescription } from '@/components/ui/card';
import { Bot, CheckCircle2, Circle, Clock, KanbanSquare, Loader2, Play, LayoutDashboard, Target, Zap, ArrowRightCircle, Plus } from 'lucide-react';
import { Project, Phase } from '@shared/types/project';
import { Task } from '@shared/types/task';
import { Badge } from '@/components/ui/badge';
import { BackgroundAnimation } from '@/components/ui/background-animation';
import { recomputeTaskStatuses } from '@shared/lib/workflow-execution';
import { cn } from '@shared/lib/utils';

export default function ProjectDashboardPage() {
    const { id } = useParams();

    // 1. ALL HOOKS AT TOP LEVEL
    const [projectData, setProjectData] = useState<{ project: Project, phases: Phase[], tasks: Task[] } | null>(null);
    const [nextAction, setNextAction] = useState<{ next_task: Task | null, reasoning: string } | null>(null);
    const [loading, setLoading] = useState(true);
    const [chatMessages, setChatMessages] = useState([
        { role: 'assistant', text: "Hello strategist. System initialized. I'm analyzing your workflow architecture now." }
    ]);
    const [chatInput, setChatInput] = useState('');

    // 2. Fetch Logic
    useEffect(() => {
        let active = true;
        async function fetchDashboard() {
            try {
                const [projectRes, actionRes] = await Promise.all([
                    fetch(`/api/projects/${id}`),
                    fetch(`/api/ai/next-action?project_id=${id}`)
                ]);
                if (!active) return;
                if (projectRes.ok) {
                    const pData = await projectRes.json();
                    setProjectData(pData);
                }
                if (actionRes.ok) {
                    const aData = await actionRes.json();
                    setNextAction(aData);
                }
            } catch (error) {
                console.error("Dashboard failed to load", error);
            } finally {
                if (active) setLoading(false);
            }
        }
        fetchDashboard();
        return () => { active = false; };
    }, [id]);

    // 3. Data Processing (Safe against null projectData)
    const project = projectData?.project;
    const initialTasks = projectData?.tasks || [];

    const localUser = (typeof window !== 'undefined' && id) ? localStorage.getItem(`workflow_user_tasks_${id}`) : null;
    const localRemoved = (typeof window !== 'undefined' && id) ? localStorage.getItem(`workflow_removed_tasks_${id}`) : null;
    const userTasks: Task[] = localUser ? JSON.parse(localUser) : [];
    const removedIds = new Set(localRemoved ? JSON.parse(localRemoved) : []);

    const mergedTasks = [
        ...initialTasks.filter((t: Task) => !removedIds.has(t.id)),
        ...userTasks
    ];

    let demoFallback: Task[] = [];
    if (project?.is_demo_project && mergedTasks.length === 0) {
        const now = new Date().toISOString();
        demoFallback = [
            { id: 't1', title: 'Strategy Briefing', description: 'Align product mission with market needs.', status: 'DONE', task_type: 'HUMAN', graph_order: 1, level: 0, phase_id: 'p1', task_order: 1, created_at: now, meta: { source: 'AI', is_removed: false }, depends_on: [] },
            { id: 't1-a', title: 'Competitor Intelligence', description: 'Analyze market gaps.', status: 'DONE', task_type: 'AI', graph_order: 1.1, level: 1, parent_id: 't1', phase_id: 'p1', task_order: 1, created_at: now, meta: { source: 'AI', is_removed: false }, depends_on: [] },
            { id: 't1-b', title: 'Mission Roadmap', description: 'Define execution timeline.', status: 'DONE', task_type: 'AI', graph_order: 1.2, level: 1, parent_id: 't1', phase_id: 'p1', task_order: 2, created_at: now, meta: { source: 'AI', is_removed: false }, depends_on: [] },
            { id: 't2', title: 'Data Architecture AI', description: 'Generate optimal schema based on spec.', status: 'READY', task_type: 'AI', graph_order: 2, depends_on: ['t1'], level: 0, phase_id: 'p1', task_order: 3, created_at: now, meta: { source: 'AI', is_removed: false } },
            { id: 't3', title: 'Frontend Scaffold', description: 'Initialize core UI components.', status: 'BLOCKED', task_type: 'HUMAN', graph_order: 3, depends_on: ['t2'], level: 0, phase_id: 'p1', task_order: 4, created_at: now, meta: { source: 'AI', is_removed: false } }
        ];
    }

    const finalSet = demoFallback.length > 0 ? demoFallback : mergedTasks;
    const recomputed = recomputeTaskStatuses(finalSet);
    const totalTasks = recomputed.length;
    const completedTasks = recomputed.filter(t => t.status === 'DONE').length;
    const completionPercentage = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;
    const actionable = recomputed.filter(t => t.status === 'READY');
    const sorted = [...actionable].sort((a, b) => {
        if (a.task_type === 'AI' && b.task_type !== 'AI') return -1;
        if (a.task_type !== 'AI' && b.task_type === 'AI') return 1;
        return (a.graph_order || 0) - (b.graph_order || 0);
    });
    const recommended = sorted[0];
    const readyTasksCount = recomputed.filter(t => t.status === 'READY').length;
    const blockedTasksCount = recomputed.filter(t => t.status === 'BLOCKED').length;

    const snapshotGroups = {
        READY: recomputed.filter(t => t.status === 'READY').slice(0, 3),
        BLOCKED: recomputed.filter(t => t.status === 'BLOCKED').slice(0, 3),
    };

    // AI Message Injection Effect
    useEffect(() => {
        if (!loading && recommended && chatMessages.length === 1) {
            setChatMessages(prev => [
                ...prev,
                { role: 'assistant', text: `Analysis complete. The most efficient path forward is to start: "${recommended.title}". This will accelerate unblocking downstream dependencies.` }
            ]);
        }
    }, [loading, recommended]);

    const handleSendChat = (e: React.FormEvent) => {
        e.preventDefault();
        if (!chatInput.trim()) return;
        const userMsg = { role: 'user', text: chatInput };
        const next = [...chatMessages, userMsg];
        setChatMessages(next);
        setChatInput('');
        setTimeout(() => {
            setChatMessages(prev => [...prev, { role: 'assistant', text: "I'm currently processing your workflow data. I can help you modify tasks or generate sub-structures based on your requirements." }]);
        }, 1000);
    };

    // 4. EARLY RETURNS (SAFE because all hooks have executed)
    if (loading) {
        return (
            <div className="flex-1 flex items-center justify-center p-12 text-muted-foreground">
                <Loader2 className="w-8 h-8 animate-spin" />
            </div>
        );
    }

    if (!project) {
        return <div className="p-12 text-center text-muted-foreground">Project not found.</div>;
    }

    return (
        <div className="max-w-full mx-auto px-4 py-3 space-y-4 relative overflow-hidden h-[calc(100vh-80px)] flex flex-col bg-background/40">
            <BackgroundAnimation className="z-[-10] opacity-10" />

            {/* HIGHLIGHTED METRICS STRIP */}
            <div className="grid grid-cols-12 gap-4 bg-background/40 backdrop-blur-md rounded-2xl border border-border/40 p-4 shadow-xl shadow-black/5 relative overflow-hidden group">
                <div className="absolute inset-0 bg-gradient-to-r from-primary/5 via-transparent to-primary/5 opacity-0 group-hover:opacity-100 transition-opacity duration-1000 pointer-events-none" />

                {/* PROJECT IDENTITY & PROGRESS */}
                <div className="col-span-12 lg:col-span-4 flex flex-col justify-center gap-3 pr-4 border-r border-border/40">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-primary/10 rounded-xl border border-primary/20">
                                <LayoutDashboard className="w-4 h-4 text-primary" />
                            </div>
                            <h1 className="text-lg font-black tracking-tighter text-foreground/90 truncate max-w-[200px]">{project.title}</h1>
                        </div>
                        <Badge variant="outline" className="text-[9px] font-black uppercase tracking-widest bg-emerald-500/10 text-emerald-600 border-emerald-500/20">Active Mission</Badge>
                    </div>

                    <div className="space-y-1.5">
                        <div className="flex items-center justify-between px-1">
                            <span className="text-[10px] font-black uppercase text-muted-foreground/60 tracking-widest leading-none">Mission Completion</span>
                            <span className="text-[11px] font-black text-primary">{completionPercentage}%</span>
                        </div>
                        <div className="h-2.5 bg-muted/60 rounded-full overflow-hidden border border-border/20 shadow-inner">
                            <div
                                className="h-full bg-gradient-to-r from-primary/80 to-primary transition-all duration-1000 rounded-full relative"
                                style={{ width: `${completionPercentage}%` }}
                            >
                                <div className="absolute inset-0 bg-[linear-gradient(45deg,rgba(255,255,255,0.1)_25%,transparent_25%,transparent_50%,rgba(255,255,255,0.1)_50%,rgba(255,255,255,0.1)_75%,transparent_75%,transparent)] bg-[length:1rem_1rem] animate-[shimmer_2s_linear_infinite]" />
                            </div>
                        </div>
                    </div>
                </div>

                {/* KPI CARDS */}
                <div className="col-span-12 lg:col-span-6 grid grid-cols-4 gap-3">
                    {[
                        { label: 'Total Items', count: totalTasks, color: 'bg-muted/40 text-muted-foreground', icon: <Target className="w-3.5 h-3.5" /> },
                        { label: 'Completed', count: completedTasks, color: 'bg-emerald-500/10 text-emerald-600 border-emerald-500/20', icon: <CheckCircle2 className="w-3.5 h-3.5" /> },
                        { label: 'Ready to Start', count: readyTasksCount, color: 'bg-primary/10 text-primary border-primary/20', icon: <Zap className="w-3.5 h-3.5" /> },
                        { label: 'Blocked Items', count: blockedTasksCount, color: 'bg-amber-500/10 text-amber-600 border-amber-500/20', icon: <Clock className="w-3.5 h-3.5" /> }
                    ].map((kpi, idx) => (
                        <div key={idx} className={cn("p-3 rounded-2xl border flex flex-col gap-2 transition-all hover:scale-[1.02] shadow-sm", kpi.color)}>
                            <div className="flex items-center justify-between">
                                {kpi.icon}
                                <span className="text-xl font-black tracking-tighter">{kpi.count}</span>
                            </div>
                            <span className="text-[8px] font-black uppercase tracking-widest opacity-80 leading-none">{kpi.label}</span>
                        </div>
                    ))}
                </div>

                {/* BOARD CTA */}
                <div className="col-span-12 lg:col-span-2 flex flex-col justify-center items-end">
                    <Link
                        href={`/project/${id}/board`}
                        className="w-full h-full min-h-[60px] bg-primary text-primary-foreground rounded-2xl flex flex-col items-center justify-center gap-1.5 shadow-xl shadow-primary/20 hover:scale-[1.02] active:scale-95 transition-all group border border-primary-foreground/10"
                    >
                        <KanbanSquare className="w-6 h-6 group-hover:rotate-6 transition-transform" />
                        <span className="text-[10px] font-black uppercase tracking-widest leading-none">Open Board</span>
                    </Link>
                </div>
            </div>

            <div className="grid grid-cols-12 gap-5 flex-1 overflow-hidden">
                {/* LEFT COLUMN */}
                <div className="col-span-12 lg:col-span-7 flex flex-col gap-5 overflow-y-auto pr-1 custom-scrollbar">

                    <Card className="border-primary/20 bg-primary/[0.03] shadow-lg shadow-primary/5 rounded-2xl overflow-hidden relative group">
                        <div className="absolute top-0 right-0 p-8 opacity-[0.03] pointer-events-none group-hover:opacity-[0.06] transition-opacity">
                            <Bot className="w-48 h-48" />
                        </div>
                        <div className="p-5 flex flex-col gap-4 relative z-10">
                            <div className="flex items-center justify-between">
                                <Badge variant="outline" className="text-[9px] font-black uppercase tracking-widest bg-primary/10 border-primary/20 text-primary px-2">AI STRATEGIST RECOMMENDATION</Badge>
                                <span className="flex items-center gap-1.5 text-[9px] font-black text-emerald-600 uppercase tracking-widest">
                                    <span className="w-1 h-1 rounded-full bg-emerald-500 animate-pulse" />
                                    Optimized Path
                                </span>
                            </div>

                            {!recommended ? (
                                <div className="py-8 text-center bg-background/40 rounded-xl border border-dashed border-border/40">
                                    <CheckCircle2 className="w-8 h-8 text-emerald-500/40 mx-auto mb-2" />
                                    <p className="text-xs font-black uppercase text-muted-foreground/60 tracking-widest">Mission Context Complete</p>
                                </div>
                            ) : (
                                <>
                                    <div className="space-y-2">
                                        <h2 className="text-2xl font-black tracking-tighter leading-[1.1]">{recommended.title}</h2>
                                        <p className="text-sm text-muted-foreground font-medium leading-relaxed max-w-xl">
                                            "{recommended.task_type === 'AI'
                                                ? `Autonomous stage identified. I can execute this technical dependency instantly to unblock ${blockedTasksCount} downstream items.`
                                                : `Prerequisite validation required. Your expert involvement is needed to ensure the structural integrity of the next phase.`}"
                                        </p>
                                    </div>
                                    <div className="flex gap-3 mt-2">
                                        <Link
                                            href={`/project/${id}/task/${recommended.id}`}
                                            className="h-10 px-6 bg-primary text-primary-foreground rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-primary/20 hover:scale-[1.02] active:scale-95 transition-all flex items-center gap-2"
                                        >
                                            <Play className="w-3.5 h-3.5 fill-current" />
                                            Start Work Item
                                        </Link>
                                        <Link
                                            href={`/project/${id}/task/${recommended.id}`}
                                            className="h-10 px-6 bg-muted/60 text-foreground rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-muted transition-all flex items-center gap-2 border border-border/40"
                                        >
                                            View Details
                                        </Link>
                                    </div>
                                </>
                            )}
                        </div>
                    </Card>

                    <div className="grid grid-cols-2 gap-4">
                        {[
                            { id: 'READY', label: 'Actionable Now', tasks: snapshotGroups.READY, border: 'border-l-primary' },
                            { id: 'BLOCKED', label: 'Waiting (Blocked)', tasks: snapshotGroups.BLOCKED, border: 'border-l-amber-500' }
                        ].map(group => (
                            <div key={group.id} className="flex flex-col gap-2">
                                <h3 className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/60 px-1">{group.label}</h3>
                                <div className="space-y-2">
                                    {group.tasks.length === 0 ? (
                                        <div className="p-4 bg-muted/20 border border-dashed border-border/40 rounded-xl text-[9px] text-center font-black uppercase text-muted-foreground/20 italic">No Items</div>
                                    ) : (
                                        group.tasks.map(t => (
                                            <Link
                                                key={t.id}
                                                href={`/project/${id}/task/${t.id}`}
                                                className={cn(
                                                    "p-3 bg-card border border-border/40 rounded-xl shadow-sm flex flex-col gap-1.5 hover:border-primary/40 transition-all group",
                                                    group.border,
                                                    t.level === 1 ? "ml-4 border-l-2 pl-3" : "border-l-4"
                                                )}
                                            >
                                                <div className="flex items-center justify-between gap-2 overflow-hidden">
                                                    <span className="text-[12px] font-black truncate text-foreground/80 group-hover:text-primary transition-colors">{t.title}</span>
                                                    <Badge variant="outline" className="text-[7px] h-3.5 px-1 uppercase font-black shrink-0">{t.task_type}</Badge>
                                                </div>
                                                {group.id === 'BLOCKED' && (
                                                    <span className="text-[8px] font-bold text-amber-600/80 uppercase truncate tracking-tighter italic opacity-60">Architect: Waiting for prerequisite</span>
                                                )}
                                            </Link>
                                        ))
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>

                    <div className="mt-2 space-y-3">
                        <h3 className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/60 px-1">Quick Orchestration</h3>
                        <div className="grid grid-cols-3 gap-3">
                            {[
                                { label: 'Add Work Item', icon: <Plus className="w-3.5 h-3.5" /> },
                                { label: 'Generate Subtasks', icon: <Play className="w-3.5 h-3.5" /> },
                                { label: 'Re-run AI Plan', icon: <Target className="w-3.5 h-3.5" /> }
                            ].map((action, i) => (
                                <button key={i} className="flex items-center justify-center gap-2 p-3 bg-card border border-border/60 rounded-xl text-[10px] font-black uppercase tracking-widest hover:border-primary/40 hover:bg-primary/5 transition-all active:scale-95">
                                    <div className="text-primary">{action.icon}</div>
                                    {action.label}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                {/* RIGHT COLUMN: AI ASSISTANT PANEL */}
                <Card className="col-span-12 lg:col-span-5 flex flex-col border-border/40 bg-card/60 backdrop-blur-sm rounded-2xl overflow-hidden shadow-2xl relative">
                    <div className="p-4 border-b border-border/40 bg-primary/[0.02] flex items-center justify-between">
                        <div className="flex items-center gap-2.5">
                            <Bot className="w-4 h-4 text-primary" />
                            <h3 className="text-sm font-black tracking-tight">AI Command Center</h3>
                        </div>
                        <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-500/10 text-emerald-500 rounded text-[9px] font-black uppercase">
                            <span className="w-1 h-1 rounded-full bg-emerald-500 animate-pulse" />
                            Live
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-4 custom-scrollbar">
                        {chatMessages.map((msg, i) => (
                            <div key={i} className={cn("max-w-[85%] rounded-2xl p-3 text-[11px] leading-relaxed shadow-sm",
                                msg.role === 'assistant' ? "bg-muted text-foreground self-start rounded-tl-none border border-border/40" : "bg-primary text-primary-foreground self-end rounded-tr-none")}>
                                {msg.text}
                            </div>
                        ))}
                    </div>

                    <form onSubmit={handleSendChat} className="p-4 pt-0">
                        <div className="flex items-center gap-2 bg-muted/50 p-2 rounded-xl border border-border/60 focus-within:border-primary/40 focus-within:ring-2 focus-within:ring-primary/5 transition-all">
                            <input
                                value={chatInput}
                                onChange={e => setChatInput(e.target.value)}
                                placeholder="Optimize current phase / add subtasks..."
                                className="flex-1 bg-transparent border-none text-[11px] outline-none placeholder:text-muted-foreground/50 px-2"
                            />
                            <button type="submit" className="h-8 w-8 bg-primary text-primary-foreground rounded-lg flex items-center justify-center hover:opacity-90 active:scale-95 transition-all">
                                <Target className="w-4 h-4 -rotate-45" />
                            </button>
                        </div>
                        <p className="text-[8px] text-center mt-3 text-muted-foreground/40 font-black uppercase tracking-widest">Architect Interaction Mode Enabled</p>
                    </form>
                </Card>

            </div>
        </div>
    );
}
